import { ComponentContext } from "@teambit/generator";

export function themeCompositionFile(context: ComponentContext) {
  return {
    relativePath: `${context.name}.composition.tsx`,
    content: `import { useTheme } from './${context.name}-provider.js';
import { ${context.namePascalCase} } from './${context.name}.js';
import { TokenViewer } from '@bitdesign/sparks.sparks-theme';

function ViewTokens() {
  const theme = useTheme();

  return <TokenViewer theme={theme} />;
}

export const LightTheme = () => {
  return (
    <${context.namePascalCase}>
      <ViewTokens />
    </${context.namePascalCase}>
  );
};

export const DarkTheme = () => {
  return (
    <${context.namePascalCase} initialTheme='dark'>
      <ViewTokens />
    </${context.namePascalCase}>
  );
};
`
  }
}
